Query.SQL:
SELECT DECODE(COUNT(*),0,'N','Y') AS "CPR.IS_CODED_PARTY" 
FROM   CASE_PARTY_ROLES CPR
,      CODED_PARTIES    CP
WHERE  CPR.CASE_NUMBER = ${param.caseNumber}
AND    CPR.PARTY_ROLE_CODE = ${param.partyRoleCode}
AND    CPR.CASE_PARTY_NO = ${param.casePartyNumber}
AND    CPR.PARTY_ID = CP.PARTY_ID
